generated_oml:
// Sensing Components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor on the permanent‑magnet synchronous motor."
]
instance MotorRotationEncoder : DTDFVocab:SensingComponent [
    base:desc "Encoder mounted on the motor shaft recording angular position."
]
instance GearboxRotationEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder on the cycloidal gearbox capturing rotation of the gearwheel."
]

// Data Transmitted (from sensors)
instance CurrentMeasurement : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]
instance MotorAngleMeasurement : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorRotationEncoder
]
instance GearboxAngleMeasurement : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxRotationEncoder
]

// Data produced from measurements
instance MotorTorqueData : DTDFVocab:Data [
    base:desc "Derived torque calculated from motor current and encoder signals."
    DTDFVocab:fromData CurrentMeasurement, MotorAngleMeasurement
    DTDFVocab:inputTo SimulinkEngine, MQTTBroker, AssetAdministrationShell
]
instance MotorOmegaData : DTDFVocab:Data [
    base:desc "Derived angular velocity of the motor shaft."
    DTDFVocab:fromData MotorAngleMeasurement
    DTDFVocab:inputTo SimulinkEngine, MQTTBroker, AssetAdministrationShell
]
instance GearboxOmegaData : DTDFVocab:Data [
    base:desc "Derived angular velocity of the gearbox output shaft."
    DTDFVocab:fromData GearboxAngleMeasurement
    DTDFVocab:inputTo SimulinkEngine, MQTTBroker, AssetAdministrationShell
]

// Acting Components
instance PermanentMagnetSyncMotor : DTDFVocab:ActingComponent [
    base:desc "Permanent‑magnet synchronous motor driving the first vertical axis."
]
instance GearboxTransmission : DTDFVocab:ActingComponent [
    base:desc "Two‑stage gear train consisting of a gear transmission and a cycloidal gearbox."
]
instance CycloidalGearbox : DTDFVocab:ActingComponent [
    base:desc "Cycloidal gearbox converting motor torque to axis rotation."
]
instance Axis : DTDFVocab:ActingComponent [
    base:desc "First vertical axis of the MABI MAX 100 industrial robot."
]

// Enablers
instance SysMLTool : DTDFVocab:Enabler [
    base:desc "SysML tool for structural and machinery modeling of the first axis."
    DTDFVocab:enables ModelValidationService
]
instance SimulinkEngine : DTDFVocab:Enabler [
    base:desc "MathWorks Simulink engine executing executable models of motor and gearboxes."
    DTDFVocab:enables FrictionIdentificationService, ModelValidationService
]
instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell providing model management for the digital shadow."
    DTDFVocab:enables DataTraceAggregationService
]
instance MQTTBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker transporting sensor data streams between the robot and the digitl twin."
    DTDFVocab:enables DataTraceAggregationService, RealTimeDashboardService
]
instance WebDashboard : DTDFVocab:Enabler [
    base:desc "Web‑based dashboard for real‑time visualization and interaction."
    DTDFVocab:enables RealTimeDashboardService
]

// Services
instance RealTimeDashboardService : DTDFVocab:Service [
    base:desc "Service providing real‑time dashboard visualization of friction and motion states."
    DTDFVocab:provides FrictionLossDetectionInsight, ControllerTuningRecommendationInsight, MaintenanceRecommendationInsight, ExperimentPlanningInsight
]
instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Service performing continuous, multi‑physics friction identification."
    DTDFVocab:provides UpdatedFrictionModelParametersInsight, UpdateFrictionModelAction
]
instance DataTraceAggregationService : DTDFVocab:Service [
    base:desc "Service aggregating data traces for analysis and experiment planning."
    DTDFVocab:provides ExperimentPlanningInsight
]
instance ModelValidationService : DTDFVocab:Service [
    base:desc "Service validating simulation models against live data."
    DTDFVocab:provides MotionAccuracyImprovementInsight
]
instance FrictionEstimateProvisionService : DTDFVocab:Service [
    base:desc "Service providing friction estimates to aid controller tuning and motion accuracy improvement."
    DTDFVocab:provides ControllerTuningRecommendationInsight, MotionAccuracyImprovementInsight
]

// Insights
instance FrictionLossDetectionInsight : DTDFVocab:Insight [
    base:desc "Detection of friction loss in the first vertical axis."
]
instance UpdatedFrictionModelParametersInsight : DTDFVocab:Insight [
    base:desc "Updated friction model parameters via iterative refinement."
]
instance MotionAccuracyImprovementInsight : DTDFVocab:Insight [
    base:desc "Improved motion accuracy through calibrated friction models."
]
instance ControllerTuningRecommendationInsight : DTDFVocab:Insight [
    base:desc "Recommendations for controller tuning based on friction estimates."
]
instance MaintenanceRecommendationInsight : DTDFVocab:Insight [
    base:desc "Recommendations for maintenance or tool changes."
]
instance ExperimentPlanningInsight : DTDFVocab:Insight [
    base:desc "Planning of subsequent experiments based on friction trend analysis."
]

// Actions
instance UpdateFrictionModelAction : DTDFVocab:Action [
    base:desc "Update the friction model parameters in the simulation."
    DTDFVocab:IsAutomatic true
]
instance TuneControllerAction : DTDFVocab:Action [
    base:desc "Tune the robot controller using friction estimates."
    DTDFVocab:IsAutomatic false
]
instance PlanExperimentAction : DTDFVocab:Action [
    base:desc "Plan and schedule further friction estimation experiments."
    DTDFVocab:IsAutomatic false
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "The digital shadow computes updated friction parameters and simulation outputs (e.g., friction‑corrected torque), which can be supplied back to the Siemens SINUMERIK 840D SS controller through a defined interface; no direct actuation occurs within the twin."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Continuous real‑time operation with sub‑second latency; friction model updates and state synchronization occur during robot operation, ensuring the twin’s state reflects the physical system in real time."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "Digital Shadow composed of a core processing component that consumes physical data traces, drives execution of simulation models, aggregates resulting data traces, and exposes them via an AAS and a dashboard; orchestrated by an underlying data‑linkage layer connecting sources to models."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Operated stage (live data capture from running robot); it also covers the design/simulation stage through incorporation of structural and behavior models for the first axis."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Traceability of data traces to generating processing components; hand‑calibrated motor dynamics model used for expected torque; continuous comparison between measured and simulated data; multi‑physics‑aware identification; verification via physical‑to‑virtual discrepancy analysis; parameter updates mitigate uncertainties."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Physical‑to‑virtual data transmission via MQTT protocol over the local network; data traces are tagged with timestamps and metadata per the Digital Shadow Reference Model."
]

instance dt_hosting_deployment : DTDFVocab:Deployment [
    base:desc "The digital shadow, processing components, and dashboard are deployed on a local server or cloud platform; the dashboard is served via a web interface; the AAS exposes models and data services over standard APIs."
]

instance horizontal_integration : DTDFVocab:HoriIntegration [
    base:desc "No horizontal integration with external systems is described; the twin operates solely within the robot’s control environment."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "SysML (ISO/IEC 42010), Asset Administration Shell (ISO 25178‑5 standard), MQTT protocol, and MBSE standard practices; alignment with ISO/IEC 42010 system architecture and MBSE modeling guidelines."
]
